public class Player
{
    public float health;
    public float currency;

    public Player(float health, float currency)
    {
        this.health = health;
        this.currency = currency;
    }
    
    public void TakeDamage(float damage)
    {
        this.health -= damage;
    }

    public bool PurchaseItem(float cost)
    {
        if (this.currency >= cost)
        {
            this.currency -= cost;
            return true;
        }
        return false;
    }
}